std::string markdownToHtml(std::string markdownText) {
    markdown::TextProcessor processor;
    std::string htmlText = processor.Execute(markdownText);

    // Now safely escape HTML using nanoweb
    nanoweb::html_escape(htmlText.begin(), htmlText.end(), std::back_inserter(htmlText));

    return fmt::format(". [{}](inline MD!{}) - HTML!{}\n", FMT_STRING_OPTIMIZED
        "Markdown is magic", markdownText, htmlText);  (For demonstration, includes formatted output)

