```javascript
const { Client, Collection, PermissionsBitField, SlashCommandBuilder } = require('discord.js@14');
const { token, banSettings } = require('./config.json');

const client = new Client({ intents: ['Guilds', 'GuildMembers', 'GuildBans'] });

client.once('ready', async () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

const banCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Bans a user from the guild.')
  .addUserOption(option => option
    .setName('user')
    .setDescription('The user to ban')
    .setRequired(true)
  )
  .addStringOption(option => option
    .setName('reason')
    .setDescription('The reason for the ban')
    .setRequired(false)
  );

const ban = async (interaction) => {
  const userToBan = interaction.options.getUser('user');
  const reason = interaction.options.getString('reason') || 'No reason provided';

  // Permission check: The command is restricted to Moderators.
  if (!interaction.member.permissions.has(PermissionsBitField.Flags.BanMembers)) {
    return interaction.reply({ content: 'You do not have permission to ban members.', ephemeral: true });
  }

  // Ban the user.
  try {
    await interaction.guild.bans.add(userToBan, { reason });
    return interaction.reply(`Successfully banned ${userToBan.tag} for reason: ${reason}`);
  } catch (error) {
    // Handle error (e.g., user not in guild)
    return interaction.reply(`Failed to ban ${userToBan.tag}. Reason: ${error.message}`);
  }
};

// Set up the interaction collector and register the command.
client.on('interactionCreate', async interaction => {
  const command = interaction.client.commands.get('ban') as any; 
  if (interaction.isCommand('ban')) return await ban(interaction);
});

// Load all commands and the ban command specifically.
client.commands = new Collection(Map);
client.commands.set('ban', banCommand.toJSON() as SlashCommandJSON);
client.application.commands.set(banCommand).then(...).catch(...).finally(readyStateCheck); 

// Login to Discord with the bot token.
client.login(token).then(console.log).catch(console.error);

// Additional cleanup and error handling code goes here...

// Listening to application command register and cache, ready for use.
client.once('interactionCreate', async interaction => {
  const commandHandler = client.commands.get('ban') as any as Function; 
  if (interaction.isCommand('ban')) await deferReply(interaction).then(commandHandler(interaction)); 
});

